            "Starting consumer topics=%s group_id=%s auto_commit=%s allow_pickle=%s strict_handlers=%s dlq=%s",
            self.config.topics,
            self.config.group_id,
            self.config.enable_auto_commit,
            self.config.allow_pickle,
            self.config.strict_handlers,
            self.config.dlq_topic,
