            try:
                self.consumer.close(autocommit=self.config.enable_auto_commit)
            except Exception:
                logger.exception("Error closing consumer")
            if self._dlq_producer is not None:
                try:
                    self._dlq_producer.close()
                except Exception:
                    logger.exception("Error closing DLQ producer")


